				Frame.Position = UDim2.new(1, 20, 0, 20 + (NotificationeIndexirus * 90))
				Frame:TweenPosition(UDim2.new(1, -290, 0, 20 + (NotificationeIndexirus * 90)), "Out", "Quad", 0.5)
	
				task.delay(duration, function()
